"""A production-quality shopping cart with discount support.

This module provides an in-memory shopping cart that tracks line items,
computes subtotals and totals, and applies discount strategies. It is
designed to keep responsibilities cleanly separated: the cart owns item
bookkeeping and arithmetic, while discounts are modelled as independent,
interchangeable strategy objects.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from decimal import Decimal
from typing import Iterable


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------


class ShoppingCartError(Exception):
    """Base class for all shopping cart errors."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product that is not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item with product name {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that already exists in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item with product name {product_name!r} already exists; "
            f"update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is negative or otherwise invalid."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative, but got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, but got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is configured with out-of-range parameters."""


# ---------------------------------------------------------------------------
# Domain model
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class CartItem:
    """A single line item in the cart.

    Instances are immutable; quantity changes produce a new ``CartItem`` via
    :meth:`with_quantity` rather than mutating in place, which keeps the cart's
    internal state easy to reason about.
    """

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line: ``unit_price * quantity``."""
        return self.unit_price * self.quantity

    def with_quantity(self, quantity: int) -> "CartItem":
        """Return a copy of this item with a different quantity."""
        return CartItem(self.product_name, self.unit_price, quantity)


# ---------------------------------------------------------------------------
# Discount strategies
# ---------------------------------------------------------------------------


class DiscountStrategy(ABC):
    """Strategy interface for reducing a subtotal to a discounted amount."""

    @abstractmethod
    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount to subtract from ``subtotal``."""
        raise NotImplementedError


@dataclass(frozen=True)
class NoDiscount(DiscountStrategy):
    """A null-object discount that never reduces the subtotal."""

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return Decimal("0")


@dataclass(frozen=True)
class PercentageDiscount(DiscountStrategy):
    """A discount expressed as a percentage of the subtotal (0–100)."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if not Decimal("0") <= self.percentage <= Decimal("100"):
            raise InvalidDiscountError(
                f"Percentage discount must be between 0 and 100, but got {self.percentage}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return subtotal * self.percentage / Decimal("100")


@dataclass(frozen=True)
class FlatDiscount(DiscountStrategy):
    """A fixed-amount discount, capped so the total never drops below zero."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < Decimal("0"):
            raise InvalidDiscountError(
                f"Flat discount must not be negative, but got {self.amount}."
            )

    def apply_to(self, subtotal: Decimal) -> Decimal:
        return min(self.amount, subtotal)


# ---------------------------------------------------------------------------
# Shopping cart
# ---------------------------------------------------------------------------


@dataclass
class ShoppingCart:
    """An in-memory shopping cart.

    The cart stores at most one line item per product name and exposes
    operations to add, remove, and re-quantify items, to apply a single
    discount strategy, and to compute monetary totals.
    """

    _items_by_name: dict[str, CartItem] = field(default_factory=dict)
    _discount: DiscountStrategy = field(default_factory=NoDiscount)

    def add_item(self, product_name: str, unit_price: Decimal, quantity: int) -> CartItem:
        """Add a new item to the cart and return it.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If ``unit_price`` is negative.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        self._validate_price(unit_price)
        self._validate_quantity(quantity)
        if product_name in self._items_by_name:
            raise DuplicateItemError(product_name)

        item = CartItem(product_name, unit_price, quantity)
        self._items_by_name[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove the item with the given product name.

        Raises:
            ItemNotFoundError: If no such product exists in the cart.
        """
        self._require_item(product_name)
        del self._items_by_name[product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing item and return the updated item.

        Raises:
            ItemNotFoundError: If no such product exists in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        self._validate_quantity(quantity)
        existing_item = self._require_item(product_name)
        updated_item = existing_item.with_quantity(quantity)
        self._items_by_name[product_name] = updated_item
        return updated_item

    def apply_discount(self, discount: DiscountStrategy) -> None:
        """Set the discount strategy applied when computing the total."""
        self._discount = discount

    def clear_discount(self) -> None:
        """Remove any applied discount, restoring full-price totals."""
        self._discount = NoDiscount()

    def calculate_subtotal(self) -> Decimal:
        """Return the sum of all line totals before any discount."""
        return sum((item.line_total for item in self._items_by_name.values()), Decimal("0"))

    def calculate_total(self) -> Decimal:
        """Return the subtotal after applying the active discount."""
        subtotal = self.calculate_subtotal()
        return subtotal - self._discount.apply_to(subtotal)

    def list_items(self) -> tuple[CartItem, ...]:
        """Return an immutable snapshot of all items in the cart."""
        return tuple(self._items_by_name.values())

    def clear(self) -> None:
        """Remove all items and reset the discount."""
        self._items_by_name.clear()
        self.clear_discount()

    def __len__(self) -> int:
        """Return the number of distinct products in the cart."""
        return len(self._items_by_name)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product name is present in the cart."""
        return product_name in self._items_by_name

    def __iter__(self) -> Iterable[CartItem]:
        """Iterate over the cart's items."""
        return iter(self._items_by_name.values())

    def _require_item(self, product_name: str) -> CartItem:
        """Return the item for ``product_name`` or raise if it is absent."""
        try:
            return self._items_by_name[product_name]
        except KeyError as missing_item:
            raise ItemNotFoundError(product_name) from missing_item

    @staticmethod
    def _validate_price(unit_price: Decimal) -> None:
        """Raise :class:`InvalidPriceError` if ``unit_price`` is negative."""
        if unit_price < Decimal("0"):
            raise InvalidPriceError(unit_price)

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        """Raise :class:`InvalidQuantityError` if ``quantity`` is not positive."""
        if not isinstance(quantity, int) or isinstance(quantity, bool) or quantity <= 0:
            raise InvalidQuantityError(quantity)
