    """Raised when a product price is negative or invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a product quantity is zero, negative, or invalid."""


class ProductNotFoundError(ShoppingCartError):
    """Raised when a requested product does not exist in the cart."""


class ProductPriceMismatchError(ShoppingCartError):
    """Raised when adding an existing product with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


@dataclass(frozen=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Defines the contract for cart discounts."""

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount for the given subtotal."""


@dataclass(frozen=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the percentage discount amount for the given subtotal."""
        return subtotal * (self.percentage / Decimal("100"))


@dataclass(frozen=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the flat discount amount for the given subtotal."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """Manages cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discounts: list[Discount] = []

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal,
        quantity: int = 1,
    ) -> None:
        """Add a new item to the cart or increase the quantity of an existing item."""
        normalized_name = self._validate_product_name(product_name)
        validated_price = self._validate_money(unit_price, "unit price")
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_name)
        if existing_item is not None:
            if existing_item.unit_price != validated_price:
                raise ProductPriceMismatchError(
                    f"Product '{normalized_name}' already exists with unit price "
                    f"{existing_item.unit_price}, not {validated_price}."
                )

            self._items[normalized_name] = replace(
                existing_item,
                quantity=existing_item.quantity + validated_quantity,
            )
            return

        self._items[normalized_name] = CartItem(
            product_name=normalized_name,
            unit_price=validated_price,
            quantity=validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._validate_product_name(product_name)
        self._get_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_item(normalized_name)

        self._items[normalized_name] = replace(
            existing_item,
            quantity=validated_quantity,
        )

    def calculate_subtotal(self) -> Decimal:
        """Return the subtotal before discounts."""
        return sum(
            (item.line_total for item in self._items.values()),
            Decimal("0"),
