        """Apply a flat discount to the cart."""
        validated_amount = self._validate_money(amount, "flat discount")
        self._discounts.append(FlatDiscount(validated_amount))

    def calculate_total(self) -> Decimal:
        """Return the final total after all discounts."""
        subtotal = self.calculate_subtotal()
        total_discount = self._calculate_total_discount(subtotal)
        return max(subtotal - total_discount, Decimal("0"))

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their details."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discounts.clear()

    def _get_item(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise ProductNotFoundError(f"Product '{product_name}' was not found in the cart.")

        return self._items[product_name]

    def _calculate_total_discount(self, subtotal: Decimal) -> Decimal:
        return sum(
            (discount.calculate(subtotal) for discount in self._discounts),
            Decimal("0"),
        )

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        normalized_name = product_name.strip()

        if not normalized_name:
            raise InvalidProductNameError("Product name must not be empty.")

        return normalized_name

